previewCss:
.darma-loader-darma-custom-597 {color: var(--loader-color, #be123c);
  --loader-secondary-color: var(--loader-secondary-color, #fda4af);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 40px;
   height: 30px;
   display: grid;
}
.darma-loader-darma-custom-597:before, .darma-loader-darma-custom-597:after  {
  content: "";
   grid-area: 1/1;
   background: currentColor;
   clip-path: polygon(0 10px,calc(100% - 15px) 10px,calc(100% - 15px) 0,100% 50%,calc(100% - 15px) 100%,calc(100% - 15px) calc(100% - 10px),0 calc(100% - 10px));
   animation: darma-loader-darma-custom-597-l4 .5s infinite alternate;
}
.darma-loader-darma-custom-597:after  {
  --s:-1;
}
@keyframes darma-loader-darma-custom-597-l4  {
  0% {transform: scale(var(--s,1)) translate(12px,-6px) translate(4px)}
100%{transform: scale(var(--s,1)) translate(12px,-6px) translate(-4px)}
}

